---@type LxAudio
local LxAudio = require("LApp.component.media.LxAudio")

---@class LxSound:LxAudio
local LxSound = classX("LxSound", LxAudio)

function LxSound:Initialize()
    self._bLoop = false
    self._pitch = 1

    self._lastName = nil
end

function LxSound:PlaySound(audioName)
    if self._isMute then return end
    self._lastName = audioName
    self:LoadAudio(audioName)
end

function LxSound:OnLoaded(audioClip, audioName)
    LxAudio.OnLoaded(self, audioClip, audioName)
    self:InternalPlay(audioClip, audioName)
end

function LxSound:InternalPlay(audioClip, audioName)
    local pitch = self._pitch --Time.timeScale
    if self._audioSource then
        if self._lastName == audioName then
            self:StopPlay()
            self._audioSource.clip = audioClip
            self._audioSource.loop = self._bLoop
            self._audioSource.pitch = pitch
            self:Play()
        end
    end
end

return LxSound
